import json
import urllib.request as request
import urllib.parse as urlparse
import socket
import ipaddress


def _is_safe_ip(ip_str):
    try:
        ip = ipaddress.ip_address(ip_str)
    except ValueError:
        return False

    # Disallow loopback, link-local, reserved, etc.
    if ip.is_loopback or ip.is_private or ip.is_link_local or ip.is_unspecified:
        return False
    if ip.is_reserved:
        return False
    # Additional reserved ranges
    reserved_ranges = [
        ipaddress.ip_network('127.0.0.0/8'),
        ipaddress.ip_network('10.0.0.0/8'),
        ipaddress.ip_network('172.16.0.0/12'),
        ipaddress.ip_network('192.168.0.0/16'),
        ipaddress.ip_network('169.254.0.0/16'),
        ipaddress.ip_network('0.0.0.0/8'),
        ipaddress.ip_network('::1/128'),
        ipaddress.ip_network('fc00::/7'),
        ipaddress.ip_network('fe80::/10'),
    ]
    for net in reserved_ranges:
        if ip in net:
            return False
    return True


def readJSON(url):
    '''
    Read a json file from a url
    and return the parsed json object
    '''
    parsed = urlparse.urlparse(url)
    if parsed.scheme not in ('http', 'https'):
        raise ValueError("Only http and https schemes are allowed")

    try:
        hostname = parsed.hostname
        if not hostname:
            raise ValueError("No hostname provided")
        ip = socket.gethostbyname(hostname)
    except Exception:
        raise ValueError("Invalid or unresolvable hostname")

    if not _is_safe_ip(ip):
        raise ValueError("Access to this IP address is not allowed")

